window.PACTO.acts["reg-2013-604"]={"label": "REGOLAMENTO (UE) N. 604/2013 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 604/2013", "file": "ext-reg-2013-604.html", "external": true, "version": "consolidato 2013-06-29", "eurlex": "https://eur-lex.europa.eu/eli/reg/2013/604/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto", "anchor": "art_1", "frags": [[null, "<p class=\"norm\">Il presente regolamento stabilisce i criteri e i meccanismi di determinazione dello Stato membro competente per l’esame di una domanda di protezione internazionale presentata in uno degli Stati membri da un cittadino di un paese terzo o da un apolide («Stato membro competente»).</p>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"norm\">Ai fini del presente regolamento si intende per:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«cittadino di un paese terzo» : qualsiasi persona che non è un cittadino dell’Unione ai sensi dell’articolo 20, paragrafo 1, TFUE e che non è cittadino di uno Stato che partecipa al presente regolamento in virtù di un accordo con l’Unione europea;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«domanda di protezione internazionale» : la domanda di protezione internazionale quale definita all’articolo 2, lettera h), della direttiva 2011/95/UE;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«richiedente» : il cittadino di un paese terzo o l’apolide che abbia manifestato la volontà di chiedere la protezione internazionale sulla quale non è stata ancora adottata una decisione definitiva;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«esame di una domanda di protezione internazionale» : l’insieme delle misure d’esame, le decisioni o le sentenze pronunciate dalle autorità competenti su una domanda di protezione internazionale conformemente alla direttiva 2013/32/UE e alla direttiva 2011/95/UE ad eccezione delle procedure volte a determinare quale sia lo Stato competente in applicazione del presente regolamento;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«ritiro di una domanda di protezione internazionale» : l’azione con la quale il richiedente mette termine, esplicitamente o tacitamente, alle procedure avviate con la presentazione della sua domanda di protezione internazionale, conformemente alla direttiva 2013/32/UE;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«beneficiario di protezione internazionale» : il cittadino di un paese terzo o l’apolide al quale è stato riconosciuto il diritto alla protezione internazionale ai sensi dell’articolo 2, lettera a), della direttiva 2011/95/UE;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"normal\">«familiari» : </p>\n<p class=\"norm\">i seguenti soggetti appartenenti alla famiglia del richiedente, purché essa sia già costituita nel paese di origine, che si trovano nel territorio degli Stati membri:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">il coniuge del richiedente o il partner non legato da vincoli di matrimonio con cui abbia una relazione stabile, qualora il diritto o la prassi dello Stato membro interessato assimilino la situazione delle coppie di fatto a quelle sposate nel quadro della normativa sui cittadini di paesi terzi,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">i figli minori delle coppie di cui al primo trattino o del richiedente, a condizione che non siano coniugati e indipendentemente dal fatto che siano figli legittimi, naturali o adottivi secondo le definizioni del diritto nazionale,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">se il richiedente è minore e non coniugato, il padre, la madre o un altro adulto responsabile per il richiedente in base alla legge o alla prassi dello Stato membro in cui si trova l’adulto,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">se il beneficiario di protezione internazionale è minore e non coniugato, il padre, la madre o un altro adulto responsabile per il beneficiario in base alla legge o alla prassi dello Stato membro in cui si trova il beneficiario;</div>\n</div>\n</div>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«parenti» : la zia o lo zio, il nonno o la nonna adulti del richiedente che si trovino nel territorio di uno Stato membro, indipendentemente dal fatto che il richiedente sia figlio legittimo, naturale o adottivo secondo le definizioni del diritto nazionale;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«minore» : il cittadino di un paese terzo o l’apolide di età inferiore agli anni diciotto;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«minore non accompagnato» : il minore che entra nel territorio degli Stati membri senza essere accompagnato da un adulto che ne sia responsabile per legge o per prassi dello Stato membro interessato, fino a quando non sia effettivamente affidato a un tale adulto; il termine include il minore che viene abbandonato dopo essere entrato nel territorio degli Stati membri;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«rappresentante» : la persona o l’organizzazione designata dagli organismi competenti per assistere e rappresentare un minore non accompagnato nelle procedure previste dal presente regolamento, allo scopo di garantirne l’interesse superiore e di esercitare la capacità giuridica di agire per suo conto, ove necessario. L’organizzazione designata come rappresentante nomina una persona responsabile di assolvere le sue funzioni nei confronti del minore, ai sensi del presente regolamento;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«titolo di soggiorno» : qualsiasi permesso rilasciato dalle autorità di uno Stato membro che autorizza il soggiorno di un cittadino di un paese terzo o di un apolide nel suo territorio, compresi i documenti che consentono all’interessato di soggiornare nel territorio nazionale nell’ambito di un regime di protezione temporanea o fino a quando avranno termine le circostanze che ostano all’esecuzione di un provvedimento di allontanamento, ad eccezione dei visti e delle autorizzazioni di soggiorno rilasciati nel periodo necessario a determinare lo Stato membro competente ai sensi del presente regolamento o durante l’esame di una domanda di protezione internazionale o di una richiesta di permesso di soggiorno;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"normal\">«visto» : </p>\n<p class=\"norm\">l’autorizzazione o la decisione di uno Stato membro necessaria per il transito o per l’ingresso ai fini di soggiorno in tale Stato membro o in diversi Stati membri. La natura del visto è illustrata dalle seguenti definizioni:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">—</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«visto per soggiorno di lunga durata» : l’autorizzazione o la decisione, emessa da uno degli Stati membri conformemente al suo diritto interno o al diritto dell’Unione, necessaria per l’ingresso ai fini di un soggiorno nel territorio di tale Stato membro per una durata superiore ai tre mesi,</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">—</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«visto per soggiorno di breve durata» : l’autorizzazione o la decisione emessa da uno Stato membro ai fini del transito o di un soggiorno previsto nel territorio di uno o più o tutti gli Stati membri la cui durata non sia superiore a tre mesi su un periodo di sei mesi a decorrere dalla data del primo ingresso nel territorio degli Stati membri,</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">—</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«visto di transito aeroportuale» : visto valido per il transito nelle zone internazionali di transito di uno o più aeroporti degli Stati membri;</p>\n</td>\n</tr>\n</table>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">n)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«rischio di fuga» : la sussistenza in un caso individuale di motivi basati su criteri obiettivi definiti dalla legge per ritenere che un richiedente o un cittadino di un paese terzo o un apolide oggetto di una procedura di trasferimento possa fuggire.</p>\n</td>\n</tr>\n</table>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "3": {"label": "Articolo 3", "heading": "Accesso alla procedura di esame di una domanda di protezione internazionale", "anchor": "art_3", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri esaminano qualsiasi domanda di protezione internazionale presentata da un cittadino di un paese terzo o da un apolide sul territorio di qualunque Stato membro, compreso alla frontiera e nelle zone di transito. Una domanda d’asilo è esaminata da un solo Stato membro, che è quello individuato come Stato competente in base ai criteri enunciati al capo III.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Quando lo Stato membro competente non può essere designato sulla base dei criteri enumerati nel presente regolamento, è competente il primo Stato membro nel quale la domanda è stata presentata.</div>\n</div>"], [null, "<p class=\"norm\">Qualora sia impossibile trasferire un richiedente verso lo Stato membro inizialmente designato come competente in quanto si hanno fondati motivi di ritenere che sussistono carenze sistemiche nella procedura di asilo e nelle condizioni di accoglienza dei richiedenti in tale Stato membro, che implichino il rischio di un trattamento inumano o degradante ai sensi dell’articolo 4 della Carta dei diritti fondamentali dell’Unione europea, lo Stato membro che ha avviato la procedura di determinazione dello Stato membro competente prosegue l’esame dei criteri di cui al capo III per verificare se un altro Stato membro possa essere designato come competente.</p>"], [null, "<p class=\"norm\">Qualora non sia possibile eseguire il trasferimento a norma del presente paragrafo verso un altro Stato membro designato in base ai criteri di cui al capo III o verso il primo Stato membro in cui la domanda è stata presentata, lo Stato membro che ha avviato la procedura di determinazione diventa lo Stato membro competente.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro mantiene la possibilità di inviare un richiedente in un paese terzo sicuro, nel rispetto delle norme e delle garanzie previste dalla direttiva 2013/32/UE.</div>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Diritto di informazione", "anchor": "art_4", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Non appena sia presentata una domanda di protezione internazionale ai sensi dell’articolo 20, paragrafo 2, in uno Stato membro, le autorità competenti dello stesso informano il richiedente dell’applicazione del presente regolamento, specificando in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le finalità del presente regolamento e le conseguenze dell’eventuale presentazione di un’altra domanda in uno Stato membro diverso, nonché le conseguenze dello spostarsi da uno Stato membro a un altro durante le fasi in cui si determina lo Stato membro competente ai sensi del presente regolamento e in cui è esaminata la domanda di protezione internazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i criteri di determinazione dello Stato membro competente, la gerarchia di tali criteri nelle varie fasi della procedura e la loro durata, compreso il fatto che una domanda di protezione internazionale presentata in uno Stato membro può comportare che tale Stato membro diventi competente ai sensi del presente regolamento anche se tale competenza non si basi su tali criteri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il colloquio personale ai sensi dell’articolo 5 e la possibilità di presentare informazioni relative alla presenza di familiari, parenti o persone legate da altri vincoli di parentela negli Stati membri, compresi i modi in cui il richiedente può presentare tali informazioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la possibilità di impugnare una decisione di trasferimento e, ove applicabile, di chiedere la sospensione del trasferimento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il fatto che le autorità competenti degli Stati membri possono scambiarsi dati relativi al richiedente al solo scopo di rispettare i loro obblighi derivanti dal presente regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il diritto di accesso ai propri dati e il diritto di chiedere che tali dati siano rettificati se inesatti o che siano cancellati se trattati illecitamente, nonché le procedure da seguire per esercitare tali diritti, compresi gli estremi delle autorità di cui all’articolo 35 e delle autorità nazionali garanti per la protezione dei dati personali che sono responsabili in merito alla tutela dei dati personali.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le informazioni di cui al paragrafo 1 sono fornite al richiedente per iscritto in una lingua che il richiedente comprende o che ragionevolmente si suppone a lui comprensibile. A questo fine gli Stati membri si avvalgono dell’opuscolo comune redatto conformemente al paragrafo 3.</div>\n</div>"], [null, "<p class=\"norm\">Ove necessario per la corretta comprensione del richiedente, le informazioni sono fornite anche oralmente, ad esempio in relazione con il colloquio personale di cui all’articolo 5.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione, mediante atti di esecuzione, redige un opuscolo comune, nonché un apposito opuscolo per i minori non accompagnati, contenenti quanto meno le informazioni di cui al paragrafo 1 del presente articolo. Detto opuscolo comune contiene anche informazioni riguardanti l’applicazione del regolamento (UE) n. 603/2013 e, in particolare, lo scopo per il quale i dati di un richiedente possono essere trattati nell’ambito di Eurodac. L’opuscolo comune è realizzato in modo da consentire agli Stati membri di completarlo con informazioni aggiuntive specifiche per ciascuno Stato membro. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 44, paragrafo 2, del presente regolamento.</div>\n</div>"]]}, "5": {"label": "Articolo 5", "heading": "Colloquio personale", "anchor": "art_5", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Al fine di agevolare la procedura di determinazione dello Stato membro competente, lo Stato membro che ha avviato la procedura di determinazione effettua un colloquio personale con il richiedente. Il colloquio permette anche la corretta comprensione delle informazioni fornite al richiedente ai sensi dell’articolo 4.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il colloquio personale può non essere effettuato qualora:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il richiedente sia fuggito; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dopo aver ricevuto le informazioni di cui all’articolo 4, il richiedente abbia già fornito informazioni pertinenti per determinare lo Stato membro competente in altro modo. Gli Stati membri che non effettuano il colloquio offrono al richiedente l’opportunità di presentare ogni altra informazione pertinente per determinare correttamente lo Stato membro competente prima che sia adottata la decisione di trasferire il richiedente verso lo Stato membro competente ai sensi dell’articolo 26, paragrafo 1.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il colloquio personale si svolge in tempo utile e, in ogni caso, prima che sia adottata la decisione di trasferire il richiedente verso lo Stato membro competente ai sensi dell’articolo 26, paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il colloquio personale é effettuato in una lingua che il richiedente comprende o che ragionevolmente si suppone a lui comprensibile e nella quale questi è in grado di comunicare. Ove necessario, gli Stati membri si avvalgono di un interprete che sia in grado di garantire una comunicazione adeguata tra il richiedente e la persona che effettua il colloquio personale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il colloquio personale si svolge in condizioni tali da garantire un’adeguata riservatezza. Esso è condotto da una persona qualificata a norma del diritto nazionale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Lo Stato membro che effettua il colloquio personale redige una sintesi scritta dello stesso che contenga almeno le principali informazioni fornite dal richiedente durante il colloquio. Tale sintesi può assumere la forma di una relazione o di un modulo standard. Lo Stato membro provvede affinché il richiedente e/o l’avvocato o altro consulente legale che rappresenta il richiedente abbiano tempestivamente accesso alla sintesi.</div>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Garanzie per i minori", "anchor": "art_6", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’interesse superiore del minore deve costituire un criterio fondamentale nell’attuazione, da parte degli Stati membri, di tutte le procedure previste dal presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono affinché un rappresentante rappresenti e/o assista un minore non accompagnato in tutte le procedure previste dal presente regolamento. Il rappresentante possiede le qualifiche e le competenze necessarie ad assicurare che durante le procedure svolte ai sensi del presente regolamento sia tenuto in considerazione l’interesse superiore del minore. Tale rappresentante ha accesso al contenuto dei documenti pertinenti della pratica del richiedente, compreso l’apposito opuscolo per i minori non accompagnati.</div>\n</div>"], [null, "<p class=\"norm\">Il presente paragrafo lascia impregiudicate le pertinenti disposizioni dell’articolo 25 della direttiva 2013/32/UE.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nel valutare l’interesse superiore del minore, gli Stati membri cooperano strettamente tra loro e tengono debito conto, in particolare, dei seguenti fattori:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le possibilità di ricongiungimento familiare;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il benessere e lo sviluppo sociale del minore;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le considerazioni di sicurezza, in particolare se sussiste un rischio che il minore sia vittima della tratta di esseri umani;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’opinione del minore, secondo la sua età e maturità.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ai fini dell’applicazione dell’articolo 8, lo Stato membro in cui il minore non accompagnato ha presentato una domanda di protezione internazionale adotta il prima possibile opportune disposizioni per identificare i familiari, i fratelli o i parenti del minore non accompagnato nel territorio degli Stati membri, sempre tutelando l’interesse superiore del minore.</div>\n</div>"], [null, "<p class=\"norm\">A tal fine, detto Stato membro può chiedere l’assistenza di organizzazioni internazionali o altre organizzazioni pertinenti e può agevolare l’accesso del minore agli uffici che svolgono attività identificative presso dette organizzazioni.</p>"], [null, "<p class=\"norm\">Il personale delle autorità competenti di cui all’articolo 35 che tratta domande relative a minori non accompagnati ha ricevuto e continua a ricevere una specifica formazione in merito alle particolari esigenze dei minori.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Al fine di facilitare l’azione appropriata per l’identificazione dei familiari, fratelli o parenti del minore non accompagnato che soggiornano nel territorio di un altro Stato membro ai sensi del paragrafo 4 del presente articolo, la Commissione adotta atti di esecuzione compreso un formulario uniforme per lo scambio di informazioni pertinenti tra Stati membri. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 44, paragrafo 2.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "7": {"label": "Articolo 7", "heading": "Gerarchia dei criteri", "anchor": "art_7", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I criteri per la determinazione dello Stato membro competente si applicano nell’ordine nel quale sono definiti dal presente capo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La determinazione dello Stato membro competente in applicazione dei criteri definiti dal presente capo avviene sulla base della situazione esistente al momento in cui il richiedente ha presentato domanda di protezione internazionale per la prima volta in uno Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini dell’applicazione dei criteri di cui agli articoli 8, 10 e 16, gli Stati membri tengono conto di qualsiasi elemento di prova disponibile per quanto riguarda la presenza nel territorio di uno Stato membro, di familiari, parenti o persone legate da altri vincoli di parentela con il richiedente, a condizione che tali prove siano prodotte prima che un altro Stato membro accolga la richiesta di presa o ripresa in carico dell’interessato ai sensi, rispettivamente, degli articoli 22 e 25, e che le precedenti domande di protezione internazionale del richiedente non siano state ancora oggetto di una prima decisione sul merito.</div>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Minori", "anchor": "art_8", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se il richiedente è un minore non accompagnato, è competente lo Stato membro nel quale si trova legalmente un familiare o un fratello del minore non accompagnato, purché ciò sia nell’interesse superiore del minore. Se il richiedente è un minore coniugato il cui coniuge non è legalmente presente nel territorio degli Stati membri, lo Stato membro competente è lo Stato membro in cui si trova legalmente il padre, la madre o un altro adulto responsabile per il minore, per legge o per prassi di detto Stato membro, o un fratello se legalmente presente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Laddove il richiedente sia un minore non accompagnato che ha un parente presente legalmente in un altro Stato membro e qualora sia accertato in base a un esame individuale che il parente può occuparsi di lui/lei, detto Stato membro provvede al ricongiungimento del minore con il(i) parente(i) ed è lo Stato membro competente, purché ciò sia nell’interesse superiore del minore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se familiari, fratelli o parenti di cui ai paragrafi 1 e 2 soggiornano in più di uno Stato membro, lo Stato membro competente è determinato sulla base dell’interesse superiore del minore non accompagnato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In mancanza di un familiare, di un fratello o di un parente di cui ai paragrafi 1 e 2, è competente lo Stato membro in cui il minore non accompagnato ha presentato la domanda di protezione internazionale, purché ciò sia nell’interesse superiore del minore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 45 riguardo all’identificazione di familiari, fratelli o parenti del minore non accompagnato; ai criteri per accertare l’esistenza di legami familiari comprovati e ai criteri per valutare la capacità di un parente di occuparsi del minore non accompagnato anche nei casi in cui familiari, fratelli o parenti del minore non accompagnato soggiornino in più di uno Stato membro. Nell’esercizio del suo potere di adottare atti delegati, la Commissione non eccede l’ambito del superiore interesse del minore previsto nell’articolo 6, paragrafo 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La Commissione stabilisce, mediante atti di esecuzione, condizioni uniformi per la consultazione e lo scambio di informazioni tra gli Stati membri. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 44, paragrafo 2.</div>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Familiari beneficiari di protezione internazionale", "anchor": "art_9", "frags": [[null, "<p class=\"norm\">Se un familiare del richiedente, a prescindere dal fatto che la famiglia fosse già costituita nel paese di origine, è stato autorizzato a soggiornare in qualità di beneficiario di protezione internazionale in uno Stato membro, tale Stato membro è competente per l’esame della domanda di protezione internazionale, purché gli interessati abbiano espresso tale desiderio per iscritto.</p>"]]}, "10": {"label": "Articolo 10", "heading": "Familiari richiedenti protezione internazionale", "anchor": "art_10", "frags": [[null, "<p class=\"norm\">Se un familiare di un richiedente ha presentato in uno Stato membro una domanda di protezione internazionale sulla quale non è ancora stata adottata una prima decisione di merito, l’esame della domanda di protezione internazionale compete a detto Stato membro, sempre che gli interessati abbiano espresso tale desiderio per iscritto.</p>"]]}, "11": {"label": "Articolo 11", "heading": "Procedura familiare", "anchor": "art_11", "frags": [[null, "<p class=\"norm\">Quando diversi familiari e/o fratelli minori non coniugati presentano una domanda di protezione internazionale nel medesimo Stato membro simultaneamente, o in date sufficientemente ravvicinate perché le procedure di determinazione dello Stato competente possano essere svolte congiuntamente, e se l’applicazione dei criteri enunciati nel presente regolamento porterebbe a trattarle separatamente, la determinazione dello Stato competente si basa sulle seguenti disposizioni:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è competente per l’esame delle domande di protezione internazionale di tutti i familiari e/o di fratelli minori non coniugati lo Stato membro che i criteri designano come competente per prendere in carico il maggior numero di essi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">negli altri casi, è competente lo Stato membro che i criteri designano come competente per l’esame della domanda del più anziano di essi.</p>\n</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Rilascio di titoli di soggiorno o visti", "anchor": "art_12", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se il richiedente è titolare di un titolo di soggiorno in corso di validità, lo Stato membro competente per l’esame della domanda di protezione internazionale è quello che ha rilasciato tale titolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se il richiedente è titolare di un visto in corso di validità, lo Stato membro competente per l’esame della domanda di protezione internazionale è quello che ha rilasciato il visto, a meno che il visto non sia stato rilasciato per conto di un altro Stato membro nel quadro di un accordo di rappresentanza ai sensi dell’articolo 8 del regolamento (CE) n. 810/2009 del Parlamento europeo e del Consiglio, del 13 luglio 2009, che istituisce un codice comunitario dei visti (\n<span class=\"superscript\">1</span>\n). In tal caso, l’esame della domanda di protezione internazionale compete allo Stato membro rappresentato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Se il richiedente è titolare di più titoli di soggiorno o visti in corso di validità, rilasciati da vari Stati membri, lo Stato membro competente per l’esame della domanda di protezione internazionale è, nell’ordine:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro che ha rilasciato il titolo di soggiorno che conferisce il diritto di soggiorno più lungo o, se la validità temporale è identica, lo Stato membro che ha rilasciato il titolo di soggiorno la cui scadenza è più lontana;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro che ha rilasciato il visto la cui scadenza è più lontana, quando i visti sono di analoga natura;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quando si tratta di visti di natura diversa, lo Stato membro che ha rilasciato il visto di validità più lunga o, in caso di validità identica, lo Stato membro che ha rilasciato il visto la cui scadenza è più lontana.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se il richiedente è titolare soltanto di uno o più titoli di soggiorno scaduti da meno di due anni o di uno o più visti scaduti da meno di sei mesi che gli avevano effettivamente permesso l’ingresso nel territorio di uno Stato membro, si applicano i paragrafi 1, 2 e 3 fino a che il richiedente non abbia lasciato i territori degli Stati membri.</div>\n</div>"], [null, "<p class=\"norm\">Qualora il richiedente sia titolare di uno o più titoli di soggiorno scaduti da oltre due anni o di uno o più visti scaduti da oltre sei mesi che gli avevano effettivamente permesso l’ingresso nel territorio di uno Stato membro e non abbia lasciato i territori degli Stati membri, è competente lo Stato membro in cui è presentata la domanda di protezione internazionale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il fatto che il titolo di soggiorno o il visto sia stato rilasciato ad un cittadino di un paese terzo che ha declinato una identità falsa o usurpata o dietro presentazione di documenti falsificati, contraffatti o non validi non osta all’attribuzione della competenza allo Stato membro che lo ha rilasciato. Tuttavia, lo Stato membro che ha rilasciato il titolo di soggiorno o il visto non è competente se può dimostrare che la frode è avvenuta successivamente al rilascio del titolo o del visto.</div>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Ingresso e/o soggiorno", "anchor": "art_13", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando è accertato, sulla base degli elementi di prova e delle circostanze indiziarie di cui ai due elenchi menzionati all’articolo 22, paragrafo 3, del presente regolamento, inclusi i dati di cui al regolamento (UE) n. 603/2013, che il richiedente ha varcato illegalmente, per via terrestre, marittima o aerea, in provenienza da un paese terzo, la frontiera di uno Stato membro, lo Stato membro in questione è competente per l’esame della domanda di protezione internazionale. Detta responsabilità cessa 12 mesi dopo la data di attraversamento clandestino della frontiera.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Quando uno Stato membro non può o non può più essere ritenuto responsabile ai sensi del paragrafo 1 del presente articolo e quando è accertato, sulla base degli elementi di prova e delle circostanze indiziarie di cui ai due elenchi menzionati all’articolo 22, paragrafo 3, che il richiedente - entrato illegalmente nei territori degli Stati membri o del quale non si possano accertare le circostanze dell’ingresso - ha soggiornato per un periodo continuato di almeno cinque mesi in uno Stato membro prima di presentare domanda di protezione internazionale, detto Stato membro è competente per l’esame della domanda di protezione internazionale.</div>\n</div>"], [null, "<p class=\"norm\">Se il richiedente ha soggiornato per periodi di almeno cinque mesi in vari Stati membri, lo Stato membro in cui ha soggiornato più di recente è competente per l’esame della domanda di protezione internazionale.</p>"]]}, "14": {"label": "Articolo 14", "heading": "Ingresso con esenzione dal visto", "anchor": "art_14", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se un cittadino di un paese terzo o un apolide entra nel territorio di uno Stato membro in cui è dispensato dal visto, l’esame della domanda di protezione internazionale compete in questo caso a tale Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il principio di cui al paragrafo 1 non si applica se il cittadino di un paese terzo o l’apolide presenta la domanda di protezione internazionale in un altro Stato membro in cui è parimenti dispensato dal visto per l’ingresso nel suo territorio. In questo caso tale altro Stato membro è competente per l’esame della domanda di protezione internazionale.</div>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Domanda nella zona internazionale di transito di un aeroporto", "anchor": "art_15", "frags": [[null, "<p class=\"norm\">Quando la volontà di chiedere la protezione internazionale è manifestata nella zona internazionale di transito di un aeroporto di uno Stato membro da un cittadino di un paese terzo o da un apolide, detto Stato membro è competente per l’esame della domanda.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "16": {"label": "Articolo 16", "heading": "Persone a carico", "anchor": "art_16", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Laddove a motivo di una gravidanza, maternità recente, malattia grave, grave disabilità o età avanzata un richiedente sia dipendente dall’assistenza del figlio, del fratello o del genitore legalmente residente in uno degli Stati membri o laddove un figlio, un fratello o un genitore legalmente residente in uno degli Stati membri sia dipendente dall’assistenza del richiedente, gli Stati membri lasciano insieme o ricongiungono il richiedente con tale figlio, fratello o genitore, a condizione che i legami familiari esistessero nel paese d’origine, che il figlio, il fratello, il genitore o il richiedente siano in grado di fornire assistenza alla persona a carico e che gli interessati abbiano espresso tale desiderio per iscritto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se il figlio, il fratello o il genitore di cui al paragrafo 1 risiede legalmente in uno Stato membro diverso da quello in cui si trova il richiedente, lo Stato membro competente è lo Stato membro in cui il figlio, il fratello e o il genitore risiede legalmente, a meno che la salute del richiedente non impedisca allo stesso, per un periodo di tempo significativo, di recarsi in detto Stato membro. In tal caso, lo Stato membro competente è lo Stato membro in cui si trova il richiedente. Detto Stato membro non è soggetto all’obbligo di condurre il figlio, il fratello o il genitore del richiedente nel suo territorio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 45 riguardo agli elementi di cui tenere conto per valutare il vincolo di dipendenza, ai criteri per accertare l’esistenza di legami familiari comprovati, ai criteri per valutare la capacità della persona in questione di occuparsi della persona a carico e agli elementi di cui tenere conto per valutare l’impossibilità di viaggiare per un periodo di tempo significativo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione stabilisce, mediante atti di esecuzione, condizioni uniformi per la consultazione e lo scambio di informazioni tra Stati membri. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 44, paragrafo 2.</div>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Clausole discrezionali", "anchor": "art_17", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 3, paragrafo 1, ciascuno Stato membro può decidere di esaminare una domanda di protezione internazionale presentata da un cittadino di un paese terzo o da un apolide, anche se tale esame non gli compete in base ai criteri stabiliti nel presente regolamento.</div>\n</div>"], [null, "<p class=\"norm\">Lo Stato membro che decide di esaminare una domanda di protezione internazionale ai sensi del presente paragrafo diventa lo Stato membro competente e assume gli obblighi connessi a tale competenza. Se applicabile, esso ne informa, utilizzando la rete telematica «DubliNet» istituita a norma dell’articolo 18 del regolamento (CE) n. 1560/2003, lo Stato membro precedentemente competente, lo Stato membro che ha in corso la procedura volta a determinare lo Stato membro competente o quello al quale è stato chiesto di prendere o riprendere in carico il richiedente.</p>"], [null, "<p class=\"norm\">Lo Stato membro che diventa competente ai sensi del presente paragrafo lo indica immediatamente nell’Eurodac ai sensi del regolamento (UE) n. 603/2013, aggiungendo la data in cui è stata adottata la decisione di esaminare la domanda.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Lo Stato membro nel quale è manifestata la volontà di chiedere la protezione internazionale e che procede alla determinazione dello Stato membro competente, o lo Stato membro competente, può, in ogni momento prima che sia adottata una prima decisione sul merito, chiedere a un altro Stato membro di prendere in carico un richiedente al fine di procedere al ricongiungimento di persone legate da qualsiasi vincolo di parentela, per ragioni umanitarie fondate in particolare su motivi familiari o culturali, anche se tale altro Stato membro non è competente ai sensi dei criteri definiti agli articoli da 8 a 11 e 16. Le persone interessate debbono esprimere il loro consenso per iscritto.</div>\n</div>"], [null, "<p class=\"norm\">La richiesta di presa in carico consta di tutti gli elementi a disposizione dello Stato membro richiedente che consentano allo Stato membro richiesto di valutare la situazione.</p>"], [null, "<p class=\"norm\">Lo Stato richiesto provvede a ogni necessaria verifica per esaminare i motivi umanitari invocati e risponde allo Stato membro richiedente entro due mesi dal ricevimento della richiesta avvalendosi della rete telematica «DubliNet» istituita a norma dell’articolo 18 del regolamento (CE) n. 1560/2003. L’eventuale risposta di rifiuto della richiesta deve essere motivata.</p>"], [null, "<p class=\"norm\">Se lo Stato membro richiesto accetta tale richiesta, la competenza dell’esame della domanda gli è trasferita.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "18": {"label": "Articolo 18", "heading": "Obblighi dello Stato membro competente", "anchor": "art_18", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Lo Stato membro competente in forza del presente regolamento è tenuto a:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">prendere in carico, alle condizioni specificate negli articoli 21, 22 e 29, il richiedente che ha presentato domanda in un altro Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">riprendere in carico, alle condizioni di cui agli articoli 23, 24, 25 e 29, il richiedente la cui domanda è in corso d’esame e che ha presentato domanda in un altro Stato membro oppure si trova nel territorio di un altro Stato membro senza un titolo di soggiorno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">riprendere in carico, alle condizioni di cui agli articoli 23, 24, 25 e 29, un cittadino di un paese terzo o un apolide che ha ritirato la sua domanda in corso d’esame e che ha presentato una domanda in un altro Stato membro o che si trova nel territorio di un altro Stato membro senza un titolo di soggiorno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">riprendere in carico, alle condizioni di cui agli articoli 23, 24, 25 e 29, un cittadino di un paese terzo o un apolide del quale è stata respinta la domanda e che ha presentato domanda in un altro Stato membro oppure si trova nel territorio di un altro Stato membro senza un titolo di soggiorno.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per quanto riguarda i casi che rientrano nell’ambito di applicazione del paragrafo 1, lettere a) e b), lo Stato membro competente esamina o porta a termine l’esame della domanda di protezione internazionale presentata dal richiedente.</div>\n</div>"], [null, "<p class=\"norm\">Nei casi che rientrano nell’ambito di applicazione del paragrafo 1, lettera c), qualora lo Stato membro competente abbia interrotto l’esame di una domanda in seguito al ritiro di quest’ultima da parte del richiedente, prima di una decisione sul merito di primo grado, detto Stato membro provvede affinché al richiedente sia concesso il diritto di chiedere che l’esame della domanda sia portato a termine o di presentare una nuova domanda di protezione internazionale, che non sarà trattata come domanda reiterata di cui alla direttiva 2013/32/UE. In tali casi gli Stati membri provvedono affinché l’esame della domanda sia portato a termine.</p>"], [null, "<p class=\"norm\">Nei casi che rientrano nell’ambito di applicazione del paragrafo 1, lettera d), qualora la domanda sia stata respinta solo in primo grado, lo Stato membro competente assicura che l’interessato abbia o abbia avuto la possibilità di ricorrere a un mezzo di impugnazione efficace ai sensi dell’articolo 46 della direttiva 2013/32/UE.</p>"]]}, "19": {"label": "Articolo 19", "heading": "Cessazione delle competenze", "anchor": "art_19", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se uno Stato membro rilascia al richiedente un titolo di soggiorno, gli obblighi previsti all’articolo 18, paragrafo 1, ricadono su detto Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli obblighi di cui all’articolo 18, paragrafo 1, vengono meno se lo Stato membro competente può stabilire, quando gli viene chiesto di prendere o riprendere in carico un richiedente o un’altra persona ai sensi dell’articolo 18, paragrafo 1, lettera c) o d), che l’interessato si è allontanato dal territorio degli Stati membri per almeno tre mesi, sempre che l’interessato non sia titolare di un titolo di soggiorno in corso di validità rilasciato dallo Stato membro competente.</div>\n</div>"], [null, "<p class=\"norm\">La domanda presentata dopo il periodo di assenza di cui al primo comma è considerata una nuova domanda e dà inizio a un nuovo procedimento di determinazione dello Stato membro competente.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli obblighi di cui all’articolo 18, paragrafo 1, lettere c) e d), vengono meno se lo Stato membro competente può stabilire, quando gli viene chiesto di riprendere in carico un richiedente o un’altra persona ai sensi dell’articolo 18, paragrafo 1, lettera c) o d), che l’interessato ha lasciato il territorio degli Stati membri conformemente a una decisione di rimpatrio o di un provvedimento di allontanamento emessa da quello Stato membro a seguito del ritiro o del rigetto della domanda.</div>\n</div>"], [null, "<p class=\"norm\">La domanda presentata dopo che avuto luogo un allontanamento effettivo è considerata una nuova domanda e dà inizio a un nuovo procedimento di determinazione dello Stato membro competente.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "20": {"label": "Articolo 20", "heading": "Avvio della procedura", "anchor": "art_20", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La procedura di determinazione dello Stato membro competente è avviata non appena una domanda di protezione internazionale è presentata per la prima volta in uno Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La domanda di protezione internazionale si considera presentata non appena le autorità competenti dello Stato membro interessato ricevono un formulario presentato dal richiedente o un verbale redatto dalle autorità. Nel caso di domanda non scritta, il periodo che intercorre dalla dichiarazione di volontà e la stesura del relativo verbale deve essere quanto più breve possibile.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini del presente regolamento, la situazione di un minore che accompagna il richiedente e risponde alla definizione di familiare, è indissociabile da quella del suo familiare e rientra nella competenza dello Stato membro competente per l’esame della domanda di protezione internazionale del suddetto familiare, anche se il minore non è personalmente un richiedente, purché ciò sia nell’interesse superiore del minore. Lo stesso trattamento è riservato ai figli nati dopo che i richiedenti sono giunti nel territorio degli Stati membri senza che sia necessario cominciare una nuova procedura di presa in carico degli stessi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Quando una domanda di protezione internazionale è presentata alle autorità competenti di uno Stato membro da un richiedente che si trova nel territorio di un altro Stato membro, la determinazione dello Stato membro competente spetta allo Stato membro nel cui territorio si trova il richiedente. Tale Stato membro è informato tempestivamente della presenza del richiedente dallo Stato membro che ha ricevuto la domanda di protezione internazionale e, ai fini del presente regolamento, è considerato lo Stato nel quale la domanda è stata presentata.</div>\n</div>"], [null, "<p class=\"norm\">Il richiedente è informato per iscritto di tale modifica nello Stato membro che ha avviato la procedura di determinazione e della data alla quale essa è avvenuta.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Lo Stato membro nel quale è stata presentata per la prima volta la domanda di protezione internazionale è tenuto, alle condizioni di cui agli articoli 23, 24, 25 e 29 e al fine di portare a termine il procedimento di determinazione dello Stato membro competente, a riprendere in carico il richiedente che si trova in un altro Stato membro senza un titolo di soggiorno o ha presentato colà una nuova domanda di protezione internazionale dopo aver ritirato la prima domanda presentata in uno Stato membro diverso durante il procedimento volto a determinare lo Stato membro competente.</div>\n</div>"], [null, "<p class=\"norm\">Tale obbligo viene meno qualora lo Stato membro tenuto a portare a termine il procedimento di determinazione dello Stato membro competente possa stabilire che il richiedente ha lasciato nel frattempo il territorio degli Stati membri per un periodo di almeno tre mesi o che un altro Stato membro gli ha rilasciato un titolo di soggiorno.</p>"], [null, "<p class=\"norm\">La domanda presentata dopo il periodo di assenza di cui al secondo comma è considerata una nuova domanda e dà inizio a una nuova procedura di determinazione dello Stato membro competente.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "21": {"label": "Articolo 21", "heading": "Presentazione di una richiesta di presa in carico", "anchor": "art_21", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Lo Stato membro che ha ricevuto una domanda di protezione internazionale e ritiene che un altro Stato membro sia competente per l’esame della stessa può chiedere a tale Stato membro di prendere in carico il richiedente quanto prima e, al più tardi, entro tre mesi dopo la presentazione della domanda ai sensi dell’articolo 20, paragrafo 2.</div>\n</div>"], [null, "<p class=\"norm\">In deroga al primo comma, nel caso di una risposta pertinente di Eurodac con dati registrati ai sensi dell’articolo 14 del regolamento (UE) n. 603/2013, la richiesta è inviata entro due mesi dal ricevimento della risposta pertinente ai sensi dell’articolo 15, paragrafo 2, di tale regolamento.</p>"], [null, "<p class=\"norm\">Se la richiesta di prendere in carico un richiedente non è formulata entro i termini previsti al primo e al secondo comma, la competenza dell’esame della domanda di protezione internazionale spetta allo Stato membro al quale la domanda è stata presentata.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Lo Stato membro richiedente può sollecitare una risposta urgente nei casi in cui la domanda di protezione internazionale sia stata presentata a seguito di un rifiuto d’ingresso o di soggiorno, di un arresto per soggiorno irregolare, della notificazione o dell’esecuzione di un provvedimento di allontanamento.</div>\n</div>"], [null, "<p class=\"norm\">La richiesta riporta i motivi che giustificano una risposta urgente e il termine entro il quale tale risposta è attesa. Tale termine è pari ad almeno una settimana.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nei casi di cui ai paragrafi 1 e 2, la richiesta di presa in carico da parte di un altro Stato membro è effettuata utilizzando un formulario uniforme e accludendo elementi di prova o circostanze indiziarie quali descritti nei due elenchi dell’articolo 22, paragrafo 3, e/o elementi pertinenti tratti dalla dichiarazione del richiedente, che permettano alle autorità dello Stato richiesto di verificare la competenza di questo in base ai criteri definiti dal presente regolamento.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione adotta, mediante atti di esecuzione, condizioni uniformi relative alla preparazione e alla presentazione delle richieste di presa in carico. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 44, paragrafo 2.</p>"]]}, "22": {"label": "Articolo 22", "heading": "Risposta a una richiesta di presa in carico", "anchor": "art_22", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Lo Stato membro richiesto procede alle verifiche necessarie e delibera sulla richiesta di presa in carico di un richiedente entro due mesi a decorrere dal ricevimento della richiesta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nella procedura di determinazione dello Stato membro competente, sono utilizzati elementi di prova e circostanze indiziarie.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione, mediante atti di esecuzione, stabilisce e riesamina periodicamente due elenchi nei quali figurano gli elementi di prova e le circostanze indiziarie pertinenti conformemente ai criteri di cui alle lettere a) e b) del presente paragrafo. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 44, paragrafo 2.</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Prove:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">si tratta di prove formali che determinano la competenza ai sensi del presente regolamento, finché non siano confutate da prove contrarie;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli Stati membri forniscono al comitato di cui all’articolo 44 modelli dei diversi tipi di documenti amministrativi, conformemente alla tipologia stabilita nell’elenco di prove formali;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">circostanze indiziarie:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">si tratta di elementi indicativi che, pur essendo oppugnabili, possono essere sufficienti, in alcuni casi, a seconda del valore probatorio ad essi attribuito;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il loro valore probatorio, in relazione alla competenza per l’esecuzione della procedura di protezione internazionale, è esaminato caso per caso.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il requisito della prova non deve andare oltre quanto necessario ai fini della corretta applicazione del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">In mancanza di prove formali, lo Stato membro richiesto si dichiara competente se le circostanze indiziarie sono coerenti, verificabili e sufficientemente particolareggiate per stabilire la competenza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Se lo Stato membro richiedente ha invocato l’urgenza, conformemente alle disposizioni dell’articolo 21, paragrafo 2, lo Stato membro richiesto compie ogni sforzo al fine di rispettare il termine indicato. In casi eccezionali, quando è possibile dimostrare che l’esame di una richiesta ai fini della presa in carico di un richiedente è particolarmente complessa, lo Stato membro richiesto può fornire la sua risposta dopo il termine richiesto, ma comunque entro un mese. In tali situazioni lo Stato membro richiesto deve comunicare la propria decisione di differire la risposta allo Stato richiedente entro il termine originariamente richiesto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">La mancata risposta entro la scadenza del termine di due mesi citato al paragrafo 1 e di quello di un mese citato al paragrafo 6 equivale all’accettazione della richiesta e comporta l’obbligo di prendere in carico la persona, compreso l’obbligo di prendere disposizioni appropriate all’arrivo della stessa.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "23": {"label": "Articolo 23", "heading": "Presentazione di una richiesta di ripresa in carico qualora sia stata presentata una nuova domanda nello Stato membro richiedente", "anchor": "art_23", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Uno Stato membro presso il quale una persona di cui all’articolo 18, paragrafo 1, lettere b), c) o d), abbia presentato una nuova domanda di protezione internazionale che ritenga che un altro Stato membro sia competente ai sensi dell’articolo 20, paragrafo 5, e dell’articolo 18, paragrafo 1, lettere b), c) o d), può chiedere all’altro Stato membro di riprendere in carico tale persona.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Una richiesta di ripresa in carico è presentata quanto prima e in ogni caso entro due mesi dal ricevimento della risposta pertinente Eurodac ai sensi dell’articolo 9, paragrafo 5, del regolamento (UE) n. 603/2013.</div>\n</div>"], [null, "<p class=\"norm\">Se la richiesta di ripresa in carico è basata su prove diverse dai dati ottenuti dal sistema Eurodac, essa è inviata allo Stato membro richiesto entro tre mesi dalla data di presentazione della domanda di protezione internazionale ai sensi dell’articolo 20, paragrafo 2.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se la richiesta di ripresa in carico non è presentata entro i termini prescritti al paragrafo 2, la competenza per l’esame della domanda di protezione internazionale spetta allo Stato membro in cui la nuova domanda è stata presentata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Una richiesta di ripresa in carico è effettuata utilizzando un formulario uniforme e comprende elementi di prova o circostanze indiziarie che figurano nelle due liste di cui all’articolo 22, paragrafo 3, e/o elementi pertinenti tratti dalle dichiarazioni dell’interessato, che permettano alle autorità dello Stato membro richiesto di verificare se è competente sulla base dei criteri stabiliti dal presente regolamento.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione adotta, mediante atti di esecuzione, condizioni uniformi per la preparazione e la presentazione delle richieste di ripresa in carico. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 44, paragrafo 2.</p>"]]}, "24": {"label": "Articolo 24", "heading": "Presentazione di una richiesta di ripresa in carico qualora non sia stata presentata una nuova domanda nello Stato membro richiedente", "anchor": "art_24", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Uno Stato membro sul cui territorio una persona di cui all’articolo 18, paragrafo 1, lettere b), c) o d), soggiorna senza un titolo di soggiorno e presso cui non è stata presentata una nuova domanda di protezione internazionale che ritenga che un altro Stato membro sia competente ai sensi dell’articolo 20, paragrafo 5, e dell’articolo 18, paragrafo 1, lettere b), c) o d), può chiedere all’altro Stato membro di riprendere in carico tale persona.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 6, paragrafo 2, della direttiva 2008/115/CE del Parlamento europeo e del Consiglio, del 16 dicembre 2008, recante norme e procedure comuni applicabili negli Stati membri al rimpatrio di cittadini di paesi terzi il cui soggiorno è irregolare (\n<span class=\"superscript\">2</span>\n), ove uno Stato membro sul cui territorio una persona soggiorna senza un titolo di soggiorno decida di consultare il sistema Eurodac ai sensi dell’articolo 17 del regolamento (UE) n. 603/2013, la richiesta di ripresa in carico di una persona di cui all’articolo 18, paragrafo 1, lettere b) o c), del presente regolamento o di una persona di cui al suo articolo 18, paragrafo 1, lettera d), la cui domanda di protezione internazionale non è stata respinta con una decisione definitiva è presentata quanto prima e in ogni caso entro due mesi dal ricevimento della risposta pertinente Eurodac ai sensi dell’articolo 17, paragrafo 5, del regolamento (UE) n. 603/2013.</div>\n</div>"], [null, "<p class=\"norm\">Se la richiesta di ripresa in carico è basata su prove diverse dai dati ottenuti dal sistema Eurodac, essa è inviata allo Stato membro richiesto entro tre mesi dalla data in cui lo Stato membro richiedente apprende che un altro Stato membro può essere competente per detta persona.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se la richiesta di ripresa in carico non è presentata entro i termini prescritti al paragrafo 2, lo Stato membro sul cui territorio l’interessato soggiorna senza titolo di soggiorno gli offre la possibilità di presentare una nuova domanda.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora una persona di cui all’articolo 18, paragrafo 1, lettera d), del presente regolamento, la cui domanda di protezione internazionale sia stata respinta con decisione definitiva in uno Stato membro, si trovi nel territorio di un altro Stato membro senza un titolo di soggiorno, quest’ultimo Stato membro può chiedere al primo Stato membro di riprendere in carico l’interessato o di avviare una procedura di rimpatrio ai sensi della direttiva 2008/115/CE.</div>\n</div>"], [null, "<p class=\"norm\">Se il secondo Stato membro decide di chiedere al primo Stato membro di riprendere in carico l’interessato, non si applicano le norme previste dalla direttiva 2008/15/CE.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La richiesta di ripresa in carico della persona di cui all’articolo 18, paragrafo 1, lettere b), c) o d), è effettuata utilizzando un formulario uniforme e comprende elementi di prova o circostanze indiziarie che figurano nei due elenchi di cui all’articolo 22, paragrafo 3, e/o elementi pertinenti tratti dalle dichiarazioni dell’interessato, che permettano alle autorità dello Stato membro richiesto di verificare se è competente sulla base dei criteri stabiliti dal presente regolamento.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione, mediante atti di esecuzione, stabilisce e riesamina periodicamente i due elenchi nei quali figurano gli elementi di prova e le circostanze indiziarie pertinenti conformemente ai criteri di cui all’articolo 22, paragrafo 3, lettere a) e b), e adotta condizioni uniformi per la preparazione e la presentazione delle richieste di ripresa in carico. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 44, paragrafo 2.</p>"]]}, "25": {"label": "Articolo 25", "heading": "Risposta a una richiesta di ripresa in carico", "anchor": "art_25", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Lo Stato membro richiesto procede alle verifiche necessarie e decide in merito alla richiesta di ripresa in carico dell’interessato quanto prima e in ogni caso entro il termine di un mese dalla data in cui perviene la richiesta. Quando la richiesta è basata su dati ottenuti dal sistema Eurodac, tale termine è ridotto a due settimane.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’assenza di risposta entro la scadenza del termine di un mese o di due settimane previsto al paragrafo 1 equivale all’accettazione della richiesta e comporta l’obbligo di riprendere in carico l’interessato, compreso l’obbligo di adottare disposizioni appropriate all’arrivo dello stesso.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "26": {"label": "Articolo 26", "heading": "Notifica di una decisione di trasferimento", "anchor": "art_26", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando lo Stato membro richiesto accetta di prendere o riprendere in carico un richiedente o un’altra persona di cui all’articolo 18, paragrafo 1, lettera c) o d), lo Stato membro richiedente notifica all’interessato la decisione di trasferirlo verso lo Stato membro competente e, se del caso, di non esaminare la sua domanda di protezione internazionale. Se l’interessato è rappresentato da un avvocato o un altro consulente legale, gli Stati membri possono scegliere di notificare la decisione a tale avvocato o consulente legale invece che all’interessato e, se del caso, comunicare la decisione all’interessato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La decisione di cui al paragrafo 1 contiene informazioni sui mezzi di impugnazione disponibili, compreso quello sul diritto di chiedere l’effetto sospensivo, ove applicabile, e sui termini per esperirli e sui termini relativi all’esecuzione del trasferimento e contiene, se necessario, le informazioni relative al luogo e alla data in cui l’interessato deve presentarsi, nel caso in cui si rechi nello Stato membro competente con i propri mezzi.</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri provvedono affinché le informazioni sulle persone o sugli enti che possono fornire assistenza legale all’interessato siano comunicate a quest’ultimo unitamente alla decisione di cui al paragrafo 1, sempre che non siano già state comunicate in precedenza.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora l’interessato non sia assistito o rappresentato da un avvocato o da un altro consulente legale, gli Stati membri lo informano dei principali elementi della decisione, e in ogni caso dei mezzi di impugnazione disponibili e dei termini per esperirli, in una lingua che il richiedente capisce o che è ragionevole supporre possa capire.</div>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Mezzi di impugnazione", "anchor": "art_27", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il richiedente o altra persona di cui all’articolo 18, paragrafo 1, lettera c) o d), ha diritto a un ricorso effettivo avverso una decisione di trasferimento, o a una revisione della medesima, in fatto e in diritto, dinanzi a un organo giurisdizionale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri stabiliscono un termine ragionevole entro il quale l’interessato può esercitare il diritto a un ricorso effettivo ai sensi del paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ai fini di ricorsi avverso decisioni di trasferimento o di revisioni delle medesime, gli Stati membri prevedono nel proprio diritto nazionale:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che il ricorso o la revisione conferisca all’interessato il diritto di rimanere nello Stato membro interessato in attesa dell’esito del ricorso o della revisione; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che il trasferimento sia automaticamente sospeso e che tale sospensione scada dopo un determinato periodo di tempo ragionevole durante il quale un organo giurisdizionale ha adottato, dopo un esame attento e rigoroso, la decisione di concedere un effetto sospensivo al ricorso o alla revisione; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che all’interessato sia offerta la possibilità di chiedere, entro un termine ragionevole, all’organo giurisdizionale di sospendere l’attuazione della decisione di trasferimento in attesa dell’esito del ricorso o della revisione della medesima. Gli Stati membri assicurano un ricorso effettivo sospendendo il trasferimento fino all’adozione della decisione sulla prima richiesta di sospensione. La decisione sulla sospensione dell’attuazione della decisione di trasferimento è adottata entro un termine ragionevole, permettendo nel contempo un esame attento e rigoroso della richiesta di sospensione. La decisione di non sospendere l’attuazione della decisione di trasferimento deve essere motivata.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono disporre che le autorità competenti possano decidere d’ufficio di sospendere l’attuazione della decisione di trasferimento in attesa dell’esito del ricorso o della revisione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri assicurano l’accesso dell’interessato all’assistenza legale nonché, se necessario, all’assistenza linguistica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono affinché l’assistenza legale sia, a richiesta, concessa gratuitamente all’interessato che non può assumersene i costi. Gli Stati membri possono prevedere, per quanto riguarda gli onorari e le altre spese, che il trattamento concesso ai richiedenti non sia più favorevole di quello di norma concesso ai propri cittadini per questioni che rientrano nell’assistenza legale.</div>\n</div>"], [null, "<p class=\"norm\">Senza limitare in modo arbitrario l’accesso all’assistenza legale, gli Stati membri possono prevedere che non sia concessa l’assistenza e la rappresentanza legali gratuite quando l’autorità competente o l’organo giurisdizionale ritengono che il ricorso o la revisione non abbiano prospettive concrete di successo.</p>"], [null, "<p class=\"norm\">Se la decisione di non concedere gratuitamente l’assistenza e la rappresentanza legale ai sensi di tale paragrafo è adottata da un’autorità diversa da un organo giurisdizionale, gli Stati membri prevedono il diritto a un ricorso effettivo dinanzi a un organo giurisdizionale avverso tale decisione.</p>"], [null, "<p class=\"norm\">Nel soddisfare i requisiti di cui al presente paragrafo, gli Stati membri garantiscono che l’assistenza e la rappresentanza legale non sia oggetto di restrizioni arbitrarie e che non sia ostacolato l’accesso del richiedente alla giustizia.</p>"], [null, "<p class=\"norm\">L’assistenza legale comprende almeno la preparazione dei documenti procedurali richiesti e la rappresentanza dinanzi all’autorità giudiziaria e può essere limitata ad avvocati o consulenti che sono specificamente designati dal diritto nazionale a fornire assistenza e rappresentanza.</p>"], [null, "<p class=\"norm\">Le modalità di accesso all’assistenza legale sono stabilite dal diritto nazionale.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "28": {"label": "Articolo 28", "heading": "Trattenimento", "anchor": "art_28", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri non possono trattenere una persona per il solo motivo che sia oggetto della procedura stabilita dal presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ove sussista un rischio notevole di fuga, gli Stati membri possono trattenere l’interessato al fine di assicurare le procedure di trasferimento a norma del presente regolamento, sulla base di una valutazione caso per caso e solo se il trattenimento è proporzionale e se non possano essere applicate efficacemente altre misure alternative meno coercitive.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il trattenimento ha durata quanto più breve possibile e non supera il tempo ragionevolmente necessario agli adempimenti amministrativi previsti da espletare con la dovuta diligenza per eseguire il trasferimento a norma del presente regolamento.</div>\n</div>"], [null, "<p class=\"norm\">Qualora una persona sia trattenuta a norma del presente articolo, il periodo per presentare una richiesta di presa o di ripresa in carico non può superare un mese dalla presentazione della domanda. Lo Stato membro che esegue la procedura a norma del presente regolamento chiede una risposta urgente in tali casi. Tale risposta è fornita entro due settimane dal ricevimento della richiesta. L’assenza di risposta entro due settimane equivale all’accettazione della richiesta e comporta l’obbligo di prendere in carico o di riprendere in carico la persona, compreso l’obbligo di adottare disposizioni appropriate all’arrivo della stessa.</p>"], [null, "<p class=\"norm\">Qualora una persona sia trattenuta a norma del presente articolo, il trasferimento di tale persona dallo Stato membro richiedente verso lo Stato membro competente deve avvenire non appena ciò sia materialmente possibile e comunque entro sei settimane dall’accettazione implicita o esplicita della richiesta da parte di un altro Stato membro di prendere o di riprendere in carico l’interessato o dal momento in cui il ricorso o la revisione non hanno più effetto sospensivo ai sensi dell’articolo 27, paragrafo 3.</p>"], [null, "<p class=\"norm\">Quando lo Stato membro richiedente non rispetta i termini per la presentazione di una richiesta di presa o ripresa in carico o qualora il trasferimento non avvenga entro il termine di sei settimane di cui al terzo comma, la persona non è più trattenuta. Gli articoli 21, 23, 24 e 29 continuano ad applicarsi di conseguenza.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Per quanto riguarda le condizioni per il trattenimento delle persone e le garanzie applicabili alle persone trattenute, al fine di assicurare le procedure di trasferimento verso lo Stato membro competente, si applicano gli articoli 9, 10 e 11 della direttiva 2013/33/UE.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "29": {"label": "Articolo 29", "heading": "Modalità e termini", "anchor": "art_29", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il trasferimento del richiedente o di altra persona ai sensi dell’articolo 18, paragrafo 1, lettera c) o d), dallo Stato membro richiedente verso lo Stato membro competente avviene conformemente al diritto nazionale dello Stato membro richiedente, previa concertazione tra gli Stati membri interessati, non appena ciò sia materialmente possibile e comunque <span>\n<span class=\"boldface\">►C1</span>\n</span> entro sei mesi dall’accettazione della richiesta da parte di un altro Stato membro di prendere o riprendere in carico l’interessato o dalla decisione definitiva su un ricorso o una revisione in caso di effetto sospensivo ai sensi dell’articolo 27, paragrafo 3.<span class=\"boldface\"> ◄ </span>\n</div>\n</div>"], [null, "<p class=\"norm\">Se i trasferimenti verso lo Stato membro competente avvengono sotto forma di partenza controllata o sotto scorta, gli Stati membri garantiscono che siano svolti in modo umano e nel pieno rispetto dei diritti fondamentali e della dignità umana.</p>"], [null, "<p class=\"norm\">Se necessario, lo Stato membro richiedente rilascia al richiedente un lasciapassare. La Commissione stabilisce, mediante atti di esecuzione, il modello del lasciapassare. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 44, paragrafo 2.</p>"], [null, "<p class=\"norm\">Lo Stato membro competente informa lo Stato membro richiedente dell’arrivo a destinazione dell’interessato o, eventualmente, del fatto che il medesimo non si è presentato nei termini prescritti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se il trasferimento non avviene entro il termine di sei mesi, lo Stato membro competente è liberato dall’obbligo di prendere o riprendere in carico l’interessato e la competenza è trasferita allo Stato membro richiedente. Questo termine può essere prorogato fino a un massimo di un anno se non è stato possibile effettuare il trasferimento a causa della detenzione dell’interessato, o fino a un massimo di diciotto mesi qualora questi sia fuggito.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se una persona è stata trasferita erroneamente o se la decisione di trasferimento è riformata in appello o in seguito a revisione dopo l’esecuzione del trasferimento, lo Stato membro che ha provveduto al trasferimento lo riprende in carico immediatamente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione stabilisce, mediante atti di esecuzione, condizioni uniformi per la consultazione e lo scambio di informazioni tra gli Stati membri, in particolare nel caso di trasferimenti differiti o ritardati, di trasferimenti a seguito di accettazione automatica, trasferimenti di minori o persone a carico e di trasferimenti sorvegliati. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 44, paragrafo 2.</div>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Costi del trasferimento", "anchor": "art_30", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I costi del trasferimento di un richiedente o altra persona di cui all’articolo 18, paragrafo 1, lettera c) o d), verso lo Stato membro competente sono a carico dello Stato membro che provvede al trasferimento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se l’interessato deve essere trasferito in uno Stato membro a seguito di un trasferimento erroneo o perché la decisione di trasferimento è stata riformata in appello o in seguito a revisione dopo l’esecuzione del trasferimento, i costi di tale rinvio sono a carico dello Stato membro che ha inizialmente provveduto al trasferimento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I costi del trasferimento non sono imputabili alle persone da trasferire a norma del presente regolamento.</div>\n</div>"]]}, "31": {"label": "Articolo 31", "heading": "Scambio di informazioni utili prima del trasferimento", "anchor": "art_31", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Lo Stato membro che provvede al trasferimento di un richiedente o di un’altra persona di cui all’articolo 18, paragrafo 1, lettera c) o d), comunica allo Stato membro competente i dati personali relativi alla persona da trasferire che sono idonei, pertinenti e non eccessivi al solo fine di garantire che le autorità competenti conformemente al diritto nazionale dello Stato membro competente siano in grado di fornire all’interessato un’assistenza adeguata, comprese le cure mediche immediate richieste per la salvaguardia dei suoi interessi vitali, e di garantire la continuità della protezione e dei diritti concessi dal presente regolamento e da altri strumenti giuridici pertinenti in materia di asilo. Tali dati sono comunicati allo Stato membro competente entro un periodo ragionevole prima del trasferimento, al fine di garantire che le sue autorità competenti conformemente al diritto nazionale dispongano di un lasso di tempo sufficiente per adottare le misure necessarie.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nella misura in cui l’autorità competente dispone delle pertinenti informazioni conformemente al diritto nazionale, lo Stato membro che effettua il trasferimento trasmette allo Stato membro competente qualsiasi informazione che ritiene necessaria per tutelare i diritti e le esigenze specifiche immediate della persona da trasferire, in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualsiasi misura immediata che lo Stato membro competente deve adottare onde far sì che siano adeguatamente soddisfatte le esigenze particolari della persona da trasferire, comprese eventuali cure mediche immediate che possono essere richieste;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli eventuali estremi di familiari, parenti o persone legate da altri vincoli di parentela nello Stato membro destinatario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso dei minori, informazioni sulla loro istruzione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una stima dell’età di un richiedente.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo scambio di informazioni ai sensi del presente articolo avviene unicamente tra autorità notificate alla Commissione ai sensi dell’articolo 35 del presente regolamento tramite la rete telematica «DubliNet» istituita a norma dell’articolo 18 del regolamento (CE) n. 1560/2003. Le informazioni scambiate possono essere utilizzate soltanto per le finalità previste dal paragrafo 1 del presente articolo e non sono oggetto di ulteriore trattamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Al fine di agevolare lo scambio di informazioni tra gli Stati membri, la Commissione redige, mediante atti di esecuzione, un formulario uniforme per il trasferimento dei dati richiesti ai sensi del presente articolo. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 44, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Allo scambio di informazioni a norma del presente articolo si applicano le disposizioni di cui all’articolo 34, paragrafi da 8 a 12.</div>\n</div>"]]}, "32": {"label": "Articolo 32", "heading": "Scambio di dati sanitari prima di un trasferimento", "anchor": "art_32", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Al solo scopo di somministrare assistenza medica o terapie, in particolare a disabili, anziani, donne in stato di gravidanza, minori e persone che hanno subito torture, stupri o altre forme gravi di violenza psicologica, fisica o sessuale, lo Stato membro che provvede al trasferimento comunica, qualora la competente autorità ne disponga conformemente al diritto nazionale, informazioni allo Stato membro competente su eventuali esigenze specifiche della persona da trasferire, ivi compresi, in determinati casi, dati sullo stato di salute fisica e mentale di tale persona. Dette informazioni sono trasferite in un certificato sanitario comune con i necessari documenti acclusi. Lo Stato membro competente assicura che si provveda adeguatamente a tali esigenze specifiche, prestando in particolare cure mediche essenziali.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione redige, mediante atti di esecuzione, il certificato sanitario comune. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 44, paragrafo 2.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Lo Stato membro che provvede al trasferimento trasmette allo Stato membro competente le informazioni di cui al paragrafo 1 soltanto previo consenso esplicito del richiedente e/o del suo rappresentante o, se il richiedente si trova nell’incapacità fisica o giuridica di dare il proprio consenso, quando tale trasmissione è necessaria per la salvaguardia degli interessi vitali del richiedente o di un’altra persona. Il mancato consenso, compreso un rifiuto del consenso, non osta al trasferimento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il trattamento dei dati personali sanitari di cui al paragrafo 1 è effettuato unicamente da un professionista della sanità che è tenuto al segreto professionale ai sensi del diritto nazionale o di norme stabilite da organismi nazionali competenti, o da altra persona soggetta a un equivalente obbligo di segretezza professionale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Lo scambio di informazioni ai sensi del presente articolo avviene unicamente tra professionisti della sanità o altre persone di cui al paragrafo 3. Le informazioni scambiate possono essere utilizzate soltanto per le finalità previste al paragrafo 1 e non sono oggetto di ulteriore trattamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione adotta, mediante atti di esecuzione, condizioni uniformi e modalità pratiche per lo scambio di informazioni di cui al paragrafo 1 del presente articolo. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 44, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Allo scambio di informazioni a norma del presente articolo si applicano le disposizioni di cui all’articolo 34, paragrafi da 8 a 12.</div>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Meccanismo di allerta rapido, di preparazione e di gestione delle crisi", "anchor": "art_33", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora, sulla base in particolare delle informazioni ottenute dall’EASO a norma del regolamento (UE) n. 439/2010, la Commissione stabilisca che l’applicazione del presente regolamento può essere ostacolata da un rischio comprovato di speciale pressione sul sistema di asilo di uno Stato membro e/o da problemi nel funzionamento del sistema di asilo di uno Stato membro, in cooperazione con l’EASO, rivolge raccomandazioni a tale Stato membro invitandolo a redigere un piano d’azione preventivo.</div>\n</div>"], [null, "<p class=\"norm\">Lo Stato membro interessato informa il Consiglio e la Commissione della sua intenzione di presentare un piano d’azione preventivo al fine di porre rimedio alla pressione e/o ai problemi nel funzionamento del sistema di asilo pur garantendo la protezione dei diritti fondamentali dei richiedenti la protezione internazionale.</p>"], [null, "<p class=\"norm\">Uno Stato membro può redigere, su propria discrezione e iniziativa, un piano d’azione preventivo e procedere alle revisioni successive del medesimo. Nell’elaborare tale piano, lo Stato membro può chiedere l’assistenza della Commissione, di altri Stati membri, dell’EASO e di altre agenzie pertinenti dell’Unione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Quando è redatto un piano d’azione preventivo, lo Stato membro interessato lo sottopone unitamente alle relazioni periodiche sull’attuazione del medesimo al Consiglio e alla Commissione. Quest’ultima informa pertanto il Parlamento europeo in merito agli elementi principali del piano d’azione preventivo. La Commissione presenta le relazioni sull’attuazione del piano al Consiglio e le trasmette al Parlamento europeo.</div>\n</div>"], [null, "<p class=\"norm\">Lo Stato membro interessato adotta tutte le misure appropriate per affrontare la situazione di speciale pressione sul suo sistema di asilo o per assicurare che le carenze individuate siano risolte prima del deteriorarsi della situazione. Qualora il piano d’azione preventivo contenga misure intese a porre rimedio alla speciale pressione sul sistema di asilo di uno Stato membro che può ostacolare l’applicazione di tale regolamento, la Commissione chiede il parere dell’EASO prima di riferire al Parlamento europeo e al Consiglio.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora la Commissione stabilisca, sulla base dell’analisi dell’EASO, che l’attuazione del piano d’azione preventivo non abbia posto rimedio alle carenze individuate o vi siano gravi rischi che la situazione in materia di asilo nello Stato membro interessato diventi critica, alla quale è improbabile porre rimedio con un piano d’azione preventivo, essa, in cooperazione con l’EASO, se del caso, può chiedere allo Stato membro interessato di redigere un piano d’azione per la gestione delle crisi e, ove necessario, provvedere alle revisioni del medesimo. Per tutta la durata del processo il piano d’azione per la gestione delle crisi assicurerà il rispetto dell’<span class=\"italics\">acquis</span> in materia di asilo dell’Unione, in particolare dei diritti fondamentali dei richiedenti protezione internazionale.</div>\n</div>"], [null, "<p class=\"norm\">In seguito alla richiesta di redigere un piano d’azione per la gestione delle crisi, lo Stato membro interessato, in cooperazione con la Commissione e l’EASO, interviene tempestivamente e al più tardi entro tre mesi dalla richiesta.</p>"], [null, "<p class=\"norm\">Lo Stato membro interessato sottopone il suo piano d’azione per la gestione delle crisi e, almeno ogni tre mesi, una relazione sull’attuazione del medesimo alla Commissione e agli altri soggetti interessati pertinenti, come, se del caso, l’EASO.</p>"], [null, "<p class=\"norm\">La Commissione informa il Parlamento europeo e il Consiglio del piano d’azione per la gestione delle crisi, delle eventuali revisioni e dell’attuazione del medesimo. In tali relazioni lo Stato membro interessato riferisce sui dati per controllare il rispetto del piano d’azione per la gestione delle crisi, quali la durata della procedura, le condizioni di trattenimento e la capacità di accoglienza in relazione all’afflusso di richiedenti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Per tutta la durata del meccanismo di allerta rapido, di preparazione e di gestione delle crisi di cui al presente articolo il Consiglio segue la situazione da vicino e può chiedere maggiori informazioni e fornire orientamenti politici, in particolare per quanto riguarda l’urgenza e la gravità della situazione e, pertanto, l’esigenza per uno Stato membro di redigere o un piano d’azione preventivo o, se necessario, un piano d’azione per la gestione delle crisi. Per tutta la durata del processo il Parlamento europeo e il Consiglio possono esaminare e fornire orientamenti in merito a eventuali misure di solidarietà che ritengano opportune.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "34": {"label": "Articolo 34", "heading": "Scambio di informazioni", "anchor": "art_34", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ciascuno Stato membro comunica allo Stato membro che ne faccia richiesta i dati di carattere personale riguardanti il richiedente che sono idonei, pertinenti e non eccessivi ai fini:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">della determinazione dello Stato membro competente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’esame della domanda di protezione internazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’attuazione di qualsiasi obbligo derivante dal presente regolamento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le informazioni di cui al paragrafo 1 possono riguardare soltanto:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati relativi all’identificazione del richiedente e, eventualmente, dei suoi familiari, parenti o persone legate da altri vincoli di parentela (cognome, nome e, eventualmente, cognome precedente; soprannomi o pseudonimi; cittadinanza, attuale e precedente, data e luogo di nascita);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i documenti d’identità e di viaggio (riferimento, periodo di validità, date di rilascio, autorità di rilascio, luogo di rilascio ecc.);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli altri elementi necessari per stabilire l’identità del richiedente, comprese le impronte digitali trattate a norma del regolamento (UE) n. 603/2013;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i luoghi di soggiorno e gli itinerari di viaggio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i titoli di soggiorno o i visti rilasciati da uno Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il luogo nel quale la domanda è stata presentata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data di presentazione di un’eventuale domanda di protezione internazionale precedente, la data di presentazione della domanda attuale, lo stato di avanzamento della procedura e l’eventuale decisione adottata.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Inoltre, e sempre che ciò sia necessario ai fini dell’esame della domanda di protezione internazionale, lo Stato membro competente può chiedere a un altro Stato membro di comunicargli le ragioni invocate dal richiedente a sostegno della sua domanda e le ragioni dell’eventuale decisione adottata nei suoi confronti. L’altro Stato membro può rifiutare di dare seguito alla richiesta se la comunicazione delle informazioni può ledere i suoi interessi fondamentali o la protezione delle libertà e dei diritti fondamentali della persona interessata o di terzi. In ogni caso, la comunicazione di dette informazioni è subordinata al consenso scritto del richiedente protezione internazionale, ottenuto dallo Stato membro richiedente. In tal caso, il richiedente deve conoscere le informazioni specifiche alla cui comunicazione acconsente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualsiasi richiesta di informazioni può essere inviata soltanto nel contesto di una specifica domanda di protezione internazionale. Essa è motivata e, quando ha per oggetto la verifica dell’esistenza di un criterio che potrebbe determinare la competenza dello Stato membro richiesto, indica su quale indizio, comprese le informazioni pertinenti, provenienti da fonti affidabili, sulle modalità e sui mezzi con cui i richiedenti entrano nei territori degli Stati membri, o elemento circostanziato e verificabile delle dichiarazioni del richiedente essa si fonda, fermo restando che tali informazioni pertinenti provenienti da fonti affidabili non sono di per sé sufficienti a determinare la responsabilità e la competenza di uno Stato membro ai sensi del presente regolamento, ma che possono contribuire alla valutazione degli ulteriori indizi relativi a un singolo richiedente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Lo Stato membro richiesto è tenuto a rispondere entro cinque settimane. Eventuali ritardi devono essere debitamente giustificati. Il mancato rispetto del termine di cinque settimane non dispensa lo Stato membro richiesto dall’obbligo di rispondere. Se dalla ricerca svolta dallo Stato membro richiesto che non abbia rispettato il termine massimo emergono informazioni che ne dimostrano la competenza, tale Stato membro non può invocare la scadenza dei termini previsti agli articoli 21, 23 e 24 come motivo per rifiutare di conformarsi alla richiesta di presa o ripresa in carico. In questo caso i termini di cui agli articoli 21, 23 e 24 per la presentazione di una richiesta di presa o ripresa in carico sono prorogati di un periodo equivalente al ritardo della risposta da parte dello Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Lo scambio di informazioni avviene dietro richiesta di uno Stato membro e può avere luogo soltanto tra le autorità di cui lo Stato membro ha dato comunicazione alla Commissione ai sensi dell’articolo 35, paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le informazioni scambiate possono essere utilizzate soltanto ai fini previsti al paragrafo 1. In ciascuno Stato membro, tali informazioni possono, secondo la loro natura e secondo la competenza dell’autorità destinataria, essere comunicate soltanto alle autorità e giurisdizioni incaricate:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">della determinazione dello Stato membro competente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’esame della domanda di protezione internazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’attuazione di qualsiasi obbligo derivante dal presente regolamento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Lo Stato membro che trasmette i dati ne garantisce l’esattezza e l’aggiornamento. Se risulta che ha trasmesso dati inesatti o che non avrebbero dovuto essere trasmessi, gli Stati membri destinatari ne sono informati immediatamente. Essi sono tenuti a rettificare tali informazioni o a cancellarle.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Il richiedente ha il diritto, dietro richiesta, di conoscere i dati trattati che lo riguardano.</div>\n</div>"], [null, "<p class=\"norm\">Se il richiedente constata che i dati sono stati trattati in violazione del presente regolamento o della direttiva 95/46/CE, soprattutto perché essi sono incompleti o inesatti, ha il diritto di ottenerne la rettifica o la cancellazione.</p>"], [null, "<p class=\"norm\">L’autorità che effettua la rettifica o la cancellazione dei dati ne dà comunicazione, a seconda dei casi, allo Stato membro emittente o destinatario delle informazioni.</p>"], [null, "<p class=\"norm\">Il richiedente ha il diritto di proporre ricorso o presentare un reclamo alle autorità o agli organi giurisdizionali competenti dello Stato membro che gli ha negato il diritto di accedere ai dati che lo riguardano o di ottenerne la rettifica o la cancellazione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">In ciascuno Stato membro interessato è fatta menzione, nel fascicolo intestato alla persona interessata e/o in un registro, della trasmissione e della ricezione delle informazioni scambiate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">I dati scambiati sono conservati per una durata non superiore a quanto necessario ai fini per i quali sono scambiati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">12.  </span>\n<div class=\"norm inline-element\">Se i dati non sono trattati automaticamente o non sono contenuti o non sono destinati ad essere inseriti in un archivio, ciascuno Stato membro adotta misure idonee per garantire il rispetto del presente articolo mediante idonei mezzi di controllo.</div>\n</div>"]]}, "35": {"label": "Articolo 35", "heading": "Autorità competenti e risorse", "anchor": "art_35", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri notificano immediatamente alla Commissione le specifiche autorità responsabili dell’esecuzione degli obblighi risultanti dal presente regolamento e gli eventuali cambiamenti in ordine alle autorità designate. Gli Stati membri provvedono affinché tali autorità dispongano delle risorse necessarie per lo svolgimento dei loro compiti e in particolare per rispondere entro i termini previsti alle richieste di informazione, alle richieste di presa in carico e alle richieste di ripresa in carico dei richiedenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione pubblica un elenco consolidato delle autorità di cui al paragrafo 1 nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>. In caso di cambiamenti, la Commissione pubblica una volta all’anno un elenco consolidato aggiornato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le autorità di cui al paragrafo 1 ricevono la necessaria formazione in merito all’applicazione del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione stabilisce, mediante atti di esecuzione, linee di comunicazione elettronica sicure tra le autorità di cui al paragrafo 1, per inviare richieste, risposte e tutta la corrispondenza scritta e per garantire che il mittente riceva automaticamente un avviso di ricevimento per via elettronica. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 44, paragrafo 2.</div>\n</div>"]]}, "36": {"label": "Articolo 36", "heading": "Disposizioni amministrative", "anchor": "art_36", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri possono concludere tra loro accordi amministrativi bilaterali relativi alle modalità pratiche di esecuzione del presente regolamento, al fine di facilitarne l’attuazione e aumentarne l’efficacia. Detti accordi possono avere per oggetto:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">scambi di ufficiali di collegamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una semplificazione delle procedure e un accorciamento dei termini applicabili alla trasmissione e all’esame delle richieste di presa in carico o di ripresa in carico dei richiedenti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono anche mantenere gli accordi amministrativi conclusi ai sensi del regolamento (CE) n. 343/2003. Qualora tali accordi non siano compatibili con il presente regolamento, gli Stati membri interessati li modificano in modo da eliminare le incompatibilità constatate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Prima di concludere o modificare un accordo di cui al paragrafo 1, lettera b), gli Stati membri interessati consultano la Commissione riguardo alla sua compatibilità con il presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora la Commissione ritenga che un accordo di cui al paragrafo 1, lettera b), sia incompatibile con il presente regolamento, lo notifica agli Stati membri interessati entro un periodo ragionevole. Gli Stati membri adottano tutti i provvedimenti appropriati per modificare l’accordo in questione entro un termine ragionevole in modo da eliminare le incompatibilità constatate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri notificano alla Commissione tutti gli accordi di cui al paragrafo 1 e le relative denunce e modifiche.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "37": {"label": "Articolo 37", "heading": "Conciliazione", "anchor": "art_37", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In caso di disaccordo persistente su qualsiasi aspetto dell’applicazione del presente regolamento, gli Stati membri possono avvalersi della procedura di conciliazione di cui al paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La procedura di conciliazione è iniziata a domanda di uno degli Stati membri in disaccordo con richiesta indirizzata al presidente del comitato istituito dall’articolo 44. Accettando di ricorrere al procedimento di conciliazione, gli Stati membri interessati si impegnano a tenere in massima considerazione la soluzione che sarà proposta.</div>\n</div>"], [null, "<p class=\"norm\">Il presidente del comitato designa tre membri del comitato, in rappresentanza di tre Stati membri estranei alla controversia. Questi ricevono per iscritto o oralmente le argomentazioni delle parti e, previa deliberazione, propongono una soluzione entro il termine di un mese, mettendola eventualmente ai voti.</p>"], [null, "<p class=\"norm\">Il presidente del comitato o il suo supplente presiede le deliberazioni. Il presidente può esprimere la sua opinione ma non partecipa al voto.</p>"], [null, "<p class=\"norm\">Che sia adottata o respinta dalle parti, la soluzione proposta è definitiva e non può formare oggetto di riesame.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "38": {"label": "Articolo 38", "heading": "Sicurezza e protezione dei dati", "anchor": "art_38", "frags": [[null, "<p class=\"norm\">Gli Stati membri adottano tutte le misure appropriate per garantire la sicurezza dei dati personali trasmessi e, in particolare, per evitare l’accesso o la divulgazione illeciti o non autorizzati, l’alterazione o la perdita dei dati personali trattati.</p>"], [null, "<p class=\"norm\">Ciascuno Stato membro provvede affinché l’autorità nazionale o le autorità di nazionali di controllo designate ai sensi dell’articolo 28, paragrafo 1, della direttiva 95/46/CE sorvegli in modo indipendente, conformemente al rispettivo diritto interno, la legittimità del trattamento, ai sensi del presente regolamento, dei dati personali da parte dello Stato membro in questione.</p>"]]}, "39": {"label": "Articolo 39", "heading": "Riservatezza", "anchor": "art_39", "frags": [[null, "<p class=\"norm\">Gli Stati membri garantiscono che le autorità di cui all’articolo 35 siano vincolate dalle norme in materia di riservatezza previste nel proprio diritto interno, relativamente a tutte le informazioni ottenute nel corso del loro lavoro.</p>"]]}, "40": {"label": "Articolo 40", "heading": "Sanzioni", "anchor": "art_40", "frags": [[null, "<p class=\"norm\">Gli Stati membri adottano le misure necessarie per garantire che qualsiasi abuso dei dati trattati ai sensi del presente regolamento sia passibile di sanzioni, anche a carattere amministrativo e/o penale conformemente al diritto nazionale, che siano effettive, proporzionate e dissuasive.</p>"]]}, "41": {"label": "Articolo 41", "heading": "Disposizioni transitorie", "anchor": "art_41", "frags": [[null, "<p class=\"norm\">Quando la domanda è stata presentata dopo la data di cui all’articolo 49, secondo comma, i fatti che potrebbero determinare la competenza di uno Stato membro in virtù delle disposizioni del presente regolamento sono presi in considerazione anche se precedenti a tale data, a esclusione di quelli indicati all’articolo 13, paragrafo 2.</p>"]]}, "42": {"label": "Articolo 42", "heading": "Calcolo dei termini", "anchor": "art_42", "frags": [[null, "<p class=\"norm\">I termini previsti dal presente regolamento si calcolano nel modo seguente:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se un termine espresso in giorni, in settimane o in mesi deve essere calcolato dal momento in cui si verifica un evento o si compie un atto, il giorno nel quale si verifica tale evento o si compie tale atto non è incluso nel termine;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un termine espresso in settimane o in mesi scade con lo spirare del giorno che, nell’ultima settimana o nell’ultimo mese ha lo stesso nome o lo stesso numero del giorno in cui si è verificato l’evento o è stato compiuto l’atto a partire dai quali il termine deve essere calcolato. Se in un termine espresso in mesi il giorno determinato per la sua scadenza manca nell’ultimo mese, il termine scade con lo spirare dell’ultimo giorno di detto mese;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i termini comprendono i sabati, le domeniche e i giorni festivi legali nello Stato membro interessato.</p>\n</div>\n</div>"]]}, "43": {"label": "Articolo 43", "heading": "Ambito di applicazione territoriale", "anchor": "art_43", "frags": [[null, "<p class=\"norm\">Per quanto riguarda la Repubblica francese, il presente regolamento si applica soltanto al suo territorio europeo.</p>"]]}, "44": {"label": "Articolo 44", "heading": "Comitato", "anchor": "art_44", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione è assistita da un comitato. Esso è un comitato ai sensi del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l’articolo 5 del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<p class=\"norm\">Se il comitato non esprime un parere, la Commissione non adotta il progetto di atto di esecuzione e si applica l’articolo 5, paragrafo 4, terzo comma, del regolamento (UE) n. 182/2011.</p>"]]}, "45": {"label": "Articolo 45", "heading": "Esercizio della delega", "anchor": "art_45", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati è conferito alla Commissione alle condizioni stabilite nel presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati di cui agli articoli 8, paragrafo 5, e 16, paragrafo 3, è conferito alla Commissione per un periodo di 5 anni a decorrere dalla data di entrata in vigore del presente regolamento. La Commissione elabora una relazione sulla delega di potere al più tardi nove mesi prima della scadenza del periodo di 5 anni. La delega di potere è tacitamente prorogata per periodi di identica durata, a meno che il Parlamento europeo o il Consiglio non si oppongano a tale proroga al più tardi tre mesi prima della scadenza di ciascun periodo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La delega di potere di cui agli articoli 8 paragrafo 5, e 16, paragrafo 3, può essere revocata in qualsiasi momento dal Parlamento europeo o dal Consiglio. La decisione di revoca pone fine alla delega di potere ivi specificata. Gli effetti della decisione decorrono dal giorno successivo alla pubblicazione della decisione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span> o da una data successiva ivi specificata. Essa non pregiudica la validità degli atti delegati già in vigore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Non appena adotta un atto delegato, la Commissione ne dà contestualmente notifica al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’atto delegato adottato ai sensi degli articoli 8 paragrafo 5, e 16, paragrafo 3, entra in vigore solo se né il Parlamento europeo né il Consiglio hanno sollevato obiezioni entro il termine di quattro mesi dalla data in cui esso è stato loro notificato o se, prima della scadenza di tale termine, sia il Parlamento europeo che il Consiglio hanno informato la Commissione che non intendono sollevare obiezioni. Tale termine è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.</div>\n</div>"]]}, "46": {"label": "Articolo 46", "heading": "Controllo e valutazione", "anchor": "art_46", "frags": [[null, "<p class=\"norm\">Entro il 21 luglio 2016, la Commissione presenta al Parlamento europeo e al Consiglio una relazione sull’applicazione del presente regolamento, proponendo all’occorrenza le necessarie modifiche. Gli Stati membri trasmettono alla Commissione qualsiasi informazione utile per la stesura della relazione al più tardi sei mesi prima di detta data.</p>"], [null, "<p class=\"norm\">Successivamente alla presentazione di tale relazione, la Commissione riferisce al Parlamento europeo e al Consiglio sull’applicazione del presente regolamento contemporaneamente alla presentazione delle relazioni sull’attuazione del sistema Eurodac di cui all’articolo 40 del regolamento (UE) n. 603/2013.</p>"]]}, "47": {"label": "Articolo 47", "heading": "Statistiche", "anchor": "art_47", "frags": [[null, "<p class=\"norm\">Ai sensi dell’articolo 4, paragrafo 4, del regolamento (CE) n. 826/2007 del Parlamento europeo e del Consiglio, dell’11 luglio 2007, relativo alle statistiche comunitarie in materia di migrazione e di protezione internazionale (\n<span class=\"superscript\">3</span>\n), gli Stati membri trasmettono alla Commissione (Eurostat) statistiche sull’applicazione del presente regolamento e del regolamento (CE) n. 1560/2003.</p>"]]}, "48": {"label": "Articolo 48", "heading": "Abrogazione", "anchor": "art_48", "frags": [[null, "<p class=\"norm\">Il regolamento (CE) n. 343/2003 è abrogato.</p>"], [null, "<p class=\"norm\">L’articolo 11, paragrafo 1, e gli articoli 13, 14 e 17 del regolamento (CE) n. 1560/2003 sono abrogati.</p>"], [null, "<p class=\"norm\">I riferimenti al regolamento abrogato o agli articoli abrogati si intendono fatti al presente regolamento e vanno letti secondo la tavola di concordanza di cui all’allegato II.</p>"]]}, "49": {"label": "Articolo 49", "heading": "Entrata in vigore e decorrenza dell’applicazione", "anchor": "art_49", "frags": [[null, "<p class=\"norm\">Il presente regolamento entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>.</p>"], [null, "<p class=\"norm\">Il presente regolamento si applica alle domande di protezione internazionale presentate a partire dal primo giorno del sesto mese successivo alla sua entrata in vigore e, da tale data, si applica ad ogni richiesta di presa in carico o di ripresa in carico di richiedenti indipendentemente dalla data di presentazione della domanda. Per le domande presentate prima di tale data, lo Stato membro competente per l’esame di una domanda di protezione internazionale è individuato conformemente ai criteri enunciati nel regolamento (CE) n. 343/2003.</p>"], [null, "<p class=\"norm\">I riferimenti nel presente regolamento al regolamento (UE) n. 603/2013, alla direttiva 2013/32/UE e alla direttiva 2013/33/UE si intendono fatti, fino alle date della loro applicazione, rispettivamente al regolamento (CE) n. 2725/2000 (\n<span class=\"superscript\">4</span>\n), alla direttiva 2003/9/CE (\n<span class=\"superscript\">5</span>\n) e alla direttiva 2005/85/CE (\n<span class=\"superscript\">6</span>\n).</p>"], [null, "<p class=\"norm\">Il presente regolamento è obbligatorio in tutti i suoi elementi e direttamente applicabile in ciascuno degli Stati membri conformemente ai trattati.</p>"], [null, "<p>\n<br/>\n</p>"], [null, "<p>\n<br/>\n</p>"]]}}, "recitals": {}};